class Solution(object):
    def countValidWords(self, sentence):
        def is_valid(word):
            if not word or any(c.isdigit() for c in word):
                return False
            hyphen_count = word.count('-')
            if hyphen_count > 1:
                return False
            if hyphen_count == 1:
                idx = word.index('-')
                if idx == 0 or idx == len(word) - 1 or not word[idx-1].isalpha() or not word[idx+1].isalpha():
                    return False
            punct_count = sum(1 for c in word if c in '!.,')
            if punct_count > 1:
                return False
            if punct_count == 1 and word[-1] not in '!.,':
                return False
            return True
        return sum(1 for word in sentence.split() if is_valid(word))
